import requests

def fetch_discography(artist_name):
    base_url = "https://api.music-discography.com/v1/artists"
    response = requests.get(f"{base_url}/{artist_name}/releases")
    if response.status_code == 200:
        return response.json()
    else:
        return None

# Example usage for Derek Nash
nash_discography = fetch_discography("Derek Nash")
print(nash_discography)
